import React, {Component} from "react";

class Equipe extends Component{
  render(){
    return (
      <div>
        <h2>Olá, sou o(a) ${this.props.nome}</h2>
        <h3>Cargo: ${this.props.cargo}</h3>
      </div>
    )
  }
}


function App() {
  return (
    <div>
        <Equipe nome="Teteus"/>      
    </div>
  );
}

export default App;
